18	typedef boost::math::policies::policy<
19	    boost::math::policies::promote_float<false >,
20	    boost::math::policies::promote_double<false >,
21	    boost::math::policies::max_root_iterations<400 >,
22	    boost::math::policies::discrete_quantile<boost::math::policies::real > > SpecialPolicy;
23	
24	// Round up to achieve correct ppf(cdf) round-trips for discrete distributions
25	typedef boost::math::policies::policy<
26	    boost::math::policies::domain_error<boost::math::policies::ignore_error >,
27	    boost::math::policies::overflow_error<boost::math::policies::user_error >,
28	    boost::math::policies::evaluation_error<boost::math::policies::user_error >,
29	    boost::math::policies::promote_float<false >,
30	    boost::math::policies::promote_double<false >,
31	    boost::math::policies::discrete_quantile<
32	        boost::math::policies::integer_round_up > > StatsPolicy;
33	
34	// Raise a RuntimeWarning making users aware that something went wrong during
35	// evaluation of the function, but return the best guess
36	template <class RealType>
37	RealType
38	boost::math::policies::user_evaluation_error(const char* function, const char* message, const RealType& val) {
39	    std::string msg("Error in function ");
40	    std::string haystack {function};
41	    const std::string needle {"%1%"};
42	    msg += haystack.replace(haystack.find(needle), needle.length(), typeid(RealType).name()) + ": ";
43	    // "message" may have %1%, but arguments don't always contain all
44	    // required information, so don't call boost::format for now
45	    msg += message;
46	    PyGILState_STATE save = PyGILState_Ensure();
47	    PyErr_WarnEx(PyExc_RuntimeWarning, msg.c_str(), 1);
48	    PyGILState_Release(save);
49	    return val;
50	}
51	
52	
53	template <class RealType>
54	RealType
55	boost::math::policies::user_overflow_error(const char* function, const char* message, const RealType& val) {
56	    std::string msg("Error in function ");
57	    std::string haystack {function};
58	    const std::string needle {"%1%"};
59	    msg += haystack.replace(haystack.find(needle), needle.length(), typeid(RealType).name()) + ": ";
60	    // From Boost docs: "overflow and underflow messages do not contain this %1% specifier
61	    //                   (since the value of value is immaterial in these cases)."
62	    if (message) {
63	        msg += message;
64	    }
65	    PyGILState_STATE save = PyGILState_Ensure();
66	    PyErr_SetString(PyExc_OverflowError, msg.c_str());
67	    PyGILState_Release(save);
68	    return 0;
